previewCss:
.darma-loader-uiverse-minimal-arc {
  display: inline-block;
  width: 38px;
  height: 38px;
  border-radius: 50%;
  border: 3px solid color-mix(in srgb, var(--loader-color, #ef4444) 18%, transparent);
  border-left-color: var(--loader-color, #ef4444);
  animation: darma-loader-uiverse-minimal-arc-spin 0.7s linear infinite;
}
@keyframes darma-loader-uiverse-minimal-arc-spin { to { transform: rotate(360deg); } }

.darma-loader-minimal-dot {
  display: inline-block;
  width: 14px;
  height: 14px;
  border-radius: 50%;
  background: var(--loader-color, #6366f1);
  animation: darma-loader-minimal-dot-minimal 0.9s ease-in-out infinite alternate;
}
@keyframes darma-loader-minimal-dot-minimal {
  from { opacity: 0.35; transform: scale(0.76); }
  to { opacity: 1; transform: scale(1); }
}

.darma-loader-minimal-line {
  display: inline-block;
  width: 72px;
  height: 3px;
  overflow: hidden;
  border-radius: 999px;
  background: color-mix(in srgb, var(--loader-color, #6366f1) 18%, transparent);
}
.darma-loader-minimal-line::before {
  content: "";
  display: block;
  width: 36%;
  height: 100%;
  border-radius: inherit;
  background: var(--loader-color, #6366f1);
  animation: darma-loader-minimal-line-line 0.9s ease-in-out infinite;
}
@keyframes darma-loader-minimal-line-line {
  0% { transform: translateX(-110%); }
  100% { transform: translateX(290%); }
}

.darma-loader-uiverse-tiny-loading-pill {
  display: inline-block;
  width: 70px;
  height: 8px;
  border-radius: 999px;
  background: color-mix(in srgb, var(--loader-color, #f97316) 16%, transparent);
  overflow: hidden;
}
.darma-loader-uiverse-tiny-loading-pill::before {
      content: "";
      display: block;
      width: 42%;
      height: 100%;
      border-radius: inherit;
      background: linear-gradient(90deg, var(--loader-color, #f97316), var(--loader-secondary-color, #fed7aa));
      animation: darma-loader-uiverse-tiny-loading-pill-progressSlide 0.95s ease-in-out infinite;
    }
    @keyframes darma-loader-uiverse-tiny-loading-pill-progressSlide { 0% { transform: translateX(-120%); } 100% { transform: translateX(260%); } }
